import{_ as i,o as a,c as t,ag as r}from"./chunks/framework.Vng7Hdlh.js";const h=JSON.parse('{"title":"User Management","description":"","frontmatter":{},"headers":[],"relativePath":"admin-ui/user-management.md","filePath":"admin-ui/user-management.md"}'),n={name:"admin-ui/user-management.md"};function s(o,e,l,c,g,u){return a(),t("div",null,[...e[0]||(e[0]=[r('<h1 id="user-management" tabindex="-1">User Management <a class="header-anchor" href="#user-management" aria-label="Permalink to &quot;User Management&quot;">​</a></h1><p>The User Management section provides comprehensive tools for managing healthcare users within the SMART on FHIR platform. This includes user registration, FHIR resource associations, permissions, and lifecycle management.</p><h2 id="👥-user-overview" tabindex="-1">👥 User Overview <a class="header-anchor" href="#👥-user-overview" aria-label="Permalink to &quot;👥 User Overview&quot;">​</a></h2><h3 id="healthcare-user-types" tabindex="-1">Healthcare User Types <a class="header-anchor" href="#healthcare-user-types" aria-label="Permalink to &quot;Healthcare User Types&quot;">​</a></h3><p>The platform supports different types of healthcare users:</p><ul><li><strong>👨‍⚕️ Practitioners</strong>: Doctors, nurses, clinicians</li><li><strong>👨‍💼 Administrative Staff</strong>: Hospital administrators, IT staff</li><li><strong>🤖 System Users</strong>: Service accounts for automated processes</li><li><strong>👤 External Users</strong>: Vendors, partners with limited access</li></ul><h3 id="user-states" tabindex="-1">User States <a class="header-anchor" href="#user-states" aria-label="Permalink to &quot;User States&quot;">​</a></h3><ul><li><strong>🟢 Active</strong>: User can authenticate and access systems</li><li><strong>🟡 Pending</strong>: Account created but not yet activated</li><li><strong>🔴 Inactive</strong>: Account disabled or suspended</li><li><strong>⚪ Archived</strong>: Historical record, no longer active</li></ul><h2 id="📝-user-registration" tabindex="-1">📝 User Registration <a class="header-anchor" href="#📝-user-registration" aria-label="Permalink to &quot;📝 User Registration&quot;">​</a></h2><h3 id="adding-new-users" tabindex="-1">Adding New Users <a class="header-anchor" href="#adding-new-users" aria-label="Permalink to &quot;Adding New Users&quot;">​</a></h3><h4 id="basic-information" tabindex="-1">Basic Information <a class="header-anchor" href="#basic-information" aria-label="Permalink to &quot;Basic Information&quot;">​</a></h4><ul><li><strong>Personal Details</strong>: First name, last name, email address</li><li><strong>Professional Info</strong>: Title, department, organization</li><li><strong>Contact Information</strong>: Phone, office location, extension</li><li><strong>Authentication</strong>: Username, temporary password settings</li></ul><h4 id="account-configuration" tabindex="-1">Account Configuration <a class="header-anchor" href="#account-configuration" aria-label="Permalink to &quot;Account Configuration&quot;">​</a></h4><ul><li><strong>Status</strong>: Set initial account state (active/pending)</li><li><strong>Permissions</strong>: Assign role-based access levels</li><li><strong>Expiration</strong>: Set account validity period if needed</li><li><strong>Notifications</strong>: Configure email and system notifications</li></ul><h3 id="bulk-user-import" tabindex="-1">Bulk User Import <a class="header-anchor" href="#bulk-user-import" aria-label="Permalink to &quot;Bulk User Import&quot;">​</a></h3><ul><li><strong>CSV Upload</strong>: Import multiple users from spreadsheet</li><li><strong>LDAP Integration</strong>: Sync with existing directory services</li><li><strong>API Import</strong>: Programmatic user creation via REST API</li><li><strong>Template Based</strong>: Use predefined user templates</li></ul><h2 id="🏥-fhir-person-associations" tabindex="-1">🏥 FHIR Person Associations <a class="header-anchor" href="#🏥-fhir-person-associations" aria-label="Permalink to &quot;🏥 FHIR Person Associations&quot;">​</a></h2><h3 id="understanding-fhir-person-resources" tabindex="-1">Understanding FHIR Person Resources <a class="header-anchor" href="#understanding-fhir-person-resources" aria-label="Permalink to &quot;Understanding FHIR Person Resources&quot;">​</a></h3><p>Each healthcare user can be associated with FHIR Person resources across multiple FHIR servers. This enables:</p><ul><li>Clinical data attribution</li><li>Cross-server identity linking</li><li>Audit trail maintenance</li><li>Consistent user representation</li></ul><h3 id="managing-associations" tabindex="-1">Managing Associations <a class="header-anchor" href="#managing-associations" aria-label="Permalink to &quot;Managing Associations&quot;">​</a></h3><h4 id="adding-fhir-associations" tabindex="-1">Adding FHIR Associations <a class="header-anchor" href="#adding-fhir-associations" aria-label="Permalink to &quot;Adding FHIR Associations&quot;">​</a></h4><ol><li><strong>Select User</strong>: Choose user from the management table</li><li><strong>Choose Server</strong>: Select target FHIR server</li><li><strong>Search/Create</strong>: Find existing Person or create new</li><li><strong>Validate</strong>: Confirm Person resource details</li><li><strong>Associate</strong>: Link user to FHIR Person resource</li></ol><h4 id="association-details" tabindex="-1">Association Details <a class="header-anchor" href="#association-details" aria-label="Permalink to &quot;Association Details&quot;">​</a></h4><ul><li><strong>Person ID</strong>: FHIR resource identifier</li><li><strong>Server</strong>: Which FHIR server hosts the resource</li><li><strong>Created Date</strong>: When association was established</li><li><strong>Last Verified</strong>: Last validation check</li><li><strong>Status</strong>: Active, pending, or error state</li></ul><h4 id="multi-server-support" tabindex="-1">Multi-Server Support <a class="header-anchor" href="#multi-server-support" aria-label="Permalink to &quot;Multi-Server Support&quot;">​</a></h4><p>Users can have Person resources on multiple FHIR servers:</p><ul><li>Primary association for main clinical data</li><li>Secondary associations for specialized systems</li><li>Cross-reference capabilities for data correlation</li><li>Unified identity across healthcare ecosystem</li></ul><h2 id="🔐-user-permissions-and-roles" tabindex="-1">🔐 User Permissions and Roles <a class="header-anchor" href="#🔐-user-permissions-and-roles" aria-label="Permalink to &quot;🔐 User Permissions and Roles&quot;">​</a></h2><h3 id="role-based-access-control-rbac" tabindex="-1">Role-Based Access Control (RBAC) <a class="header-anchor" href="#role-based-access-control-rbac" aria-label="Permalink to &quot;Role-Based Access Control (RBAC)&quot;">​</a></h3><p>The platform implements comprehensive RBAC:</p><h4 id="administrator-roles" tabindex="-1">Administrator Roles <a class="header-anchor" href="#administrator-roles" aria-label="Permalink to &quot;Administrator Roles&quot;">​</a></h4><ul><li><strong>🔑 Super Admin</strong>: Full platform access and configuration</li><li><strong>👨‍💼 System Admin</strong>: User and system management</li><li><strong>🏥 Clinical Admin</strong>: Healthcare-specific administration</li><li><strong>📊 Analytics Admin</strong>: Reporting and monitoring access</li></ul><h4 id="user-roles" tabindex="-1">User Roles <a class="header-anchor" href="#user-roles" aria-label="Permalink to &quot;User Roles&quot;">​</a></h4><ul><li><strong>👨‍⚕️ Clinician</strong>: Clinical application access</li><li><strong>📝 Data Entry</strong>: Limited data input permissions</li><li><strong>👁️ Read Only</strong>: View-only access to specific resources</li><li><strong>🔍 Auditor</strong>: Audit trail and compliance review access</li></ul><h4 id="custom-roles" tabindex="-1">Custom Roles <a class="header-anchor" href="#custom-roles" aria-label="Permalink to &quot;Custom Roles&quot;">​</a></h4><ul><li>Create organization-specific roles</li><li>Define granular permissions per role</li><li>Assign multiple roles to single user</li><li>Time-based role assignments</li></ul><h3 id="permission-matrix" tabindex="-1">Permission Matrix <a class="header-anchor" href="#permission-matrix" aria-label="Permalink to &quot;Permission Matrix&quot;">​</a></h3><p>Detailed permissions grid covering:</p><ul><li><strong>FHIR Resources</strong>: Patient, Observation, etc.</li><li><strong>Operations</strong>: Create, Read, Update, Delete, Search</li><li><strong>Scopes</strong>: System, user, patient context access</li><li><strong>Administrative</strong>: User management, configuration</li></ul><h2 id="📊-user-analytics-and-monitoring" tabindex="-1">📊 User Analytics and Monitoring <a class="header-anchor" href="#📊-user-analytics-and-monitoring" aria-label="Permalink to &quot;📊 User Analytics and Monitoring&quot;">​</a></h2><h3 id="user-activity-tracking" tabindex="-1">User Activity Tracking <a class="header-anchor" href="#user-activity-tracking" aria-label="Permalink to &quot;User Activity Tracking&quot;">​</a></h3><ul><li><strong>Login History</strong>: Authentication logs and patterns</li><li><strong>Application Usage</strong>: Which SMART apps users access</li><li><strong>Data Access</strong>: FHIR resource interactions</li><li><strong>Session Management</strong>: Active sessions and timeouts</li></ul><h3 id="compliance-reporting" tabindex="-1">Compliance Reporting <a class="header-anchor" href="#compliance-reporting" aria-label="Permalink to &quot;Compliance Reporting&quot;">​</a></h3><ul><li><strong>Access Logs</strong>: Detailed audit trails</li><li><strong>Permission Changes</strong>: History of role modifications</li><li><strong>Data Downloads</strong>: Tracking of sensitive data access</li><li><strong>Violation Alerts</strong>: Unauthorized access attempts</li></ul><h3 id="performance-metrics" tabindex="-1">Performance Metrics <a class="header-anchor" href="#performance-metrics" aria-label="Permalink to &quot;Performance Metrics&quot;">​</a></h3><ul><li><strong>Login Success Rates</strong>: Authentication failure analysis</li><li><strong>Session Duration</strong>: Average user session lengths</li><li><strong>Feature Usage</strong>: Most/least used platform features</li><li><strong>Error Patterns</strong>: Common user error scenarios</li></ul><h2 id="🔄-user-lifecycle-management" tabindex="-1">🔄 User Lifecycle Management <a class="header-anchor" href="#🔄-user-lifecycle-management" aria-label="Permalink to &quot;🔄 User Lifecycle Management&quot;">​</a></h2><h3 id="account-activation" tabindex="-1">Account Activation <a class="header-anchor" href="#account-activation" aria-label="Permalink to &quot;Account Activation&quot;">​</a></h3><ul><li><strong>Email Verification</strong>: Secure account activation process</li><li><strong>Temporary Passwords</strong>: System-generated secure passwords</li><li><strong>First Login Setup</strong>: Mandatory password change</li><li><strong>Profile Completion</strong>: Required information gathering</li></ul><h3 id="password-management" tabindex="-1">Password Management <a class="header-anchor" href="#password-management" aria-label="Permalink to &quot;Password Management&quot;">​</a></h3><ul><li><strong>Policy Enforcement</strong>: Strong password requirements</li><li><strong>Reset Capabilities</strong>: Self-service password reset</li><li><strong>Expiration Handling</strong>: Automatic password aging</li><li><strong>Multi-Factor Authentication</strong>: 2FA/MFA integration</li></ul><h3 id="account-maintenance" tabindex="-1">Account Maintenance <a class="header-anchor" href="#account-maintenance" aria-label="Permalink to &quot;Account Maintenance&quot;">​</a></h3><ul><li><strong>Profile Updates</strong>: Self-service profile management</li><li><strong>Permission Reviews</strong>: Regular access certification</li><li><strong>Account Cleanup</strong>: Automated inactive account handling</li><li><strong>Data Retention</strong>: Compliance with retention policies</li></ul><h3 id="account-termination" tabindex="-1">Account Termination <a class="header-anchor" href="#account-termination" aria-label="Permalink to &quot;Account Termination&quot;">​</a></h3><ul><li><strong>Graceful Deactivation</strong>: Preserving audit trails</li><li><strong>Data Archival</strong>: Secure historical data retention</li><li><strong>Access Revocation</strong>: Immediate permission removal</li><li><strong>Cleanup Procedures</strong>: System-wide account cleanup</li></ul><h2 id="🔍-search-and-filtering" tabindex="-1">🔍 Search and Filtering <a class="header-anchor" href="#🔍-search-and-filtering" aria-label="Permalink to &quot;🔍 Search and Filtering&quot;">​</a></h2><h3 id="advanced-search-capabilities" tabindex="-1">Advanced Search Capabilities <a class="header-anchor" href="#advanced-search-capabilities" aria-label="Permalink to &quot;Advanced Search Capabilities&quot;">​</a></h3><ul><li><strong>Text Search</strong>: Name, email, username matching</li><li><strong>Filter Options</strong>: Status, role, department, creation date</li><li><strong>FHIR Associations</strong>: Search by server or Person ID</li><li><strong>Activity Filters</strong>: Last login, recent activity patterns</li></ul><h3 id="sorting-and-organization" tabindex="-1">Sorting and Organization <a class="header-anchor" href="#sorting-and-organization" aria-label="Permalink to &quot;Sorting and Organization&quot;">​</a></h3><ul><li><strong>Column Sorting</strong>: Sortable by any user attribute</li><li><strong>Custom Views</strong>: Save frequently used filter combinations</li><li><strong>Export Options</strong>: CSV, PDF report generation</li><li><strong>Bulk Operations</strong>: Multi-user actions</li></ul><h2 id="🚨-security-and-compliance" tabindex="-1">🚨 Security and Compliance <a class="header-anchor" href="#🚨-security-and-compliance" aria-label="Permalink to &quot;🚨 Security and Compliance&quot;">​</a></h2><h3 id="security-features" tabindex="-1">Security Features <a class="header-anchor" href="#security-features" aria-label="Permalink to &quot;Security Features&quot;">​</a></h3><ul><li><strong>Account Lockout</strong>: Brute force protection</li><li><strong>IP Restrictions</strong>: Geographic and network-based limits</li><li><strong>Device Management</strong>: Trusted device registration</li><li><strong>Session Security</strong>: Secure session handling</li></ul><h3 id="compliance-support" tabindex="-1">Compliance Support <a class="header-anchor" href="#compliance-support" aria-label="Permalink to &quot;Compliance Support&quot;">​</a></h3><ul><li><strong>HIPAA Compliance</strong>: Healthcare data protection</li><li><strong>GDPR Support</strong>: Data privacy and right to erasure</li><li><strong>Audit Requirements</strong>: Comprehensive logging</li><li><strong>Access Certification</strong>: Regular permission reviews</li></ul><h3 id="data-protection" tabindex="-1">Data Protection <a class="header-anchor" href="#data-protection" aria-label="Permalink to &quot;Data Protection&quot;">​</a></h3><ul><li><strong>Encryption</strong>: All user data encrypted at rest</li><li><strong>Secure Transmission</strong>: TLS for all communications</li><li><strong>Data Minimization</strong>: Collect only necessary information</li><li><strong>Anonymization</strong>: Privacy-preserving analytics</li></ul><h2 id="🛠️-integration-capabilities" tabindex="-1">🛠️ Integration Capabilities <a class="header-anchor" href="#🛠️-integration-capabilities" aria-label="Permalink to &quot;🛠️ Integration Capabilities&quot;">​</a></h2><h3 id="external-systems" tabindex="-1">External Systems <a class="header-anchor" href="#external-systems" aria-label="Permalink to &quot;External Systems&quot;">​</a></h3><ul><li><strong>LDAP/AD Integration</strong>: Directory service synchronization</li><li><strong>SAML/OIDC</strong>: Federated identity management</li><li><strong>HR Systems</strong>: Employee database integration</li><li><strong>Badge Systems</strong>: Physical access correlation</li></ul><h3 id="api-access" tabindex="-1">API Access <a class="header-anchor" href="#api-access" aria-label="Permalink to &quot;API Access&quot;">​</a></h3><ul><li><strong>REST API</strong>: Programmatic user management</li><li><strong>Webhooks</strong>: Real-time user event notifications</li><li><strong>Bulk Operations</strong>: API-based mass user updates</li><li><strong>Synchronization</strong>: Two-way data sync capabilities</li></ul><h2 id="📱-mobile-support" tabindex="-1">📱 Mobile Support <a class="header-anchor" href="#📱-mobile-support" aria-label="Permalink to &quot;📱 Mobile Support&quot;">​</a></h2><h3 id="mobile-optimized-interface" tabindex="-1">Mobile-Optimized Interface <a class="header-anchor" href="#mobile-optimized-interface" aria-label="Permalink to &quot;Mobile-Optimized Interface&quot;">​</a></h3><ul><li><strong>Responsive Design</strong>: Optimized for all screen sizes</li><li><strong>Touch-Friendly</strong>: Mobile-first interaction design</li><li><strong>Offline Capability</strong>: Limited offline functionality</li><li><strong>Push Notifications</strong>: Mobile alert delivery</li></ul><h2 id="🎯-best-practices" tabindex="-1">🎯 Best Practices <a class="header-anchor" href="#🎯-best-practices" aria-label="Permalink to &quot;🎯 Best Practices&quot;">​</a></h2><h3 id="user-onboarding" tabindex="-1">User Onboarding <a class="header-anchor" href="#user-onboarding" aria-label="Permalink to &quot;User Onboarding&quot;">​</a></h3><ol><li><strong>Pre-registration</strong>: Collect requirements before account creation</li><li><strong>Role Assignment</strong>: Assign minimal necessary permissions initially</li><li><strong>Training</strong>: Provide platform orientation and training</li><li><strong>Gradual Access</strong>: Incrementally increase permissions as needed</li></ol><h3 id="ongoing-management" tabindex="-1">Ongoing Management <a class="header-anchor" href="#ongoing-management" aria-label="Permalink to &quot;Ongoing Management&quot;">​</a></h3><ol><li><strong>Regular Reviews</strong>: Periodic access certification</li><li><strong>Activity Monitoring</strong>: Watch for unusual usage patterns</li><li><strong>Feedback Collection</strong>: User experience improvement</li><li><strong>Documentation</strong>: Maintain up-to-date user procedures</li></ol><h3 id="security-hygiene" tabindex="-1">Security Hygiene <a class="header-anchor" href="#security-hygiene" aria-label="Permalink to &quot;Security Hygiene&quot;">​</a></h3><ol><li><strong>Password Policies</strong>: Enforce strong authentication</li><li><strong>Session Management</strong>: Monitor and control active sessions</li><li><strong>Permission Cleanup</strong>: Remove unnecessary access regularly</li><li><strong>Incident Response</strong>: Have procedures for security events</li></ol><p>The User Management system provides the foundation for secure, compliant, and efficient healthcare user administration within the SMART on FHIR ecosystem.</p><h2 id="user-federation-ldap" tabindex="-1">User Federation (LDAP) <a class="header-anchor" href="#user-federation-ldap" aria-label="Permalink to &quot;User Federation (LDAP)&quot;">​</a></h2><p>The Users page includes a <strong>User Federation</strong> sub-tab for managing LDAP directory connections. This allows importing and synchronizing users from enterprise directories (Active Directory, OpenLDAP, etc.) into Keycloak.</p><p>See the dedicated <a href="./user-federation">User Federation</a> page for full documentation on LDAP provider configuration, sync operations, and attribute mapping.</p>',87)])])}const m=i(n,[["render",s]]);export{h as __pageData,m as default};
